@app.get("/api/health")
def health():
    return {
        "status": "healthy" if INDEX_DATA else "index_not_loaded",
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "index_loaded": len(INDEX_DATA) > 0,
        "total_files": len(INDEX_DATA)
    }

@app.get("/api/stats")
def stats():
    categories = {}
    suffixes = {}
    total_size = 0
    for entry in INDEX_DATA:
        cat = entry.get("category", "unknown")
        categories[cat] = categories.get(cat, 0) + 1
        suf = entry.get("suffix", "").lower()
        suffixes[suf] = suffixes.get(suf, 0) + 1
        total_size += entry.get("size", 0)

    # Human-readable size
    def human(num):
        for unit in ['B','KB','MB','GB']:
            if num < 1024.0:
                return f"{num:.1f} {unit}"
            num /= 1024.0
        return f"{num:.1f} TB"
    return {
        "total_files": len(INDEX_DATA),
        "total_size": total_size,
        "total_size_human": human(total_size),
        "by_category": categories,
        "by_suffix": suffixes,
        "index_path": str(BRAIN_INDEX)
    }

@app.get("/api/files")
def list_files(
    category: str = None,
    suffix: str = None,
    limit: int = Query(50, ge=1, le=200),
    offset: int = Query(0, ge=0)
):
    results = INDEX_DATA
    if category:
        results = [f for f in results if f.get("category") == category]
    if suffix:
        results = [f for f in results if f.get("suffix", "").lower() == suffix.lower()]
    total = len(results)
    paginated = results[offset:offset+limit]
    return {
        "total": total,
        "limit": limit,
        "offset": offset,
        "files": paginated
    }

@app.get("/api/search")
def search(
    q: str = Query(..., min_length=1),
    fields: str = None,
    limit: int = Query(50, ge=1, le=200),
    offset: int = Query(0, ge=0)
):
    query = q.lower()
    search_fields = ['name', 'title', 'path']
    if fields:
        search_fields = [f.strip() for f in fields.split(',') if f.strip() in ['name', 'title', 'path', 'category']]

    matches = []
    for entry in INDEX_DATA:
        hit = False
        for field in search_fields:
            val = str(entry.get(field, "")).lower()
            if query in val:
                hit = True
                break
        if hit:
            matches.append(entry)

    total = len(matches)
    paginated = matches[offset:offset+limit]
    return {
        "query": q,
        "total": total,
        "limit": limit,
        "offset": offset,
        "files": paginated
    }

@app.get("/api/content")
def get_content(path: str = Query(..., min_length=1)):
    file_path = (BRAIN_ROOT / path).resolve()
    # Ensure within BRAIN_ROOT
    if not str(file_path).startswith(str(BRAIN_ROOT.resolve())):
        raise HTTPException(status_code=403, detail="Access denied: path outside Brain root")
    if not file_path.exists() or not file_path.is_file():
        raise HTTPException(status_code=404, detail="File not found")
    mime, _ = mimetypes.guess_type(str(file_path))
    if mime is None:
        mime = "text/plain"
    if mime.startswith("text/") or mime in ["application/json", "application/xml", "application/javascript", "application/x-yaml"]:
        try:
            content = file_path.read_text(encoding="utf-8")
            return PlainTextResponse(content=content, media_type=mime)
        except UnicodeDecodeError:
            return FileResponse(str(file_path), media_type="application/octet-stream")
    else:
        return FileResponse(str(file_path), media_type=mime)

